package migration

import (
	"bytes"
	"compress/gzip"
	"context"
	"crypto/sha256"
	"database/sql"
	"encoding/base64"
	"encoding/hex"
	"fmt"
	"io"
)

const (
	version4Checksum           = "d1db8d80521f879053904e109f3d5e3fcefbcb9866a2689c1258bb4cdf916700"
	version4ContractDigest     = "74d8a1991fd420cec7d3e37d25ce2f081c29577ddf21ba97815e3d54aec0b693"
	version4ContractGZIPBase64 = ""
)

var frozenVersion4Contract = mustDecodeVersion4Contract()

func Version4SchemaContract() []byte { return append([]byte(nil), frozenVersion4Contract...) }

func ValidateVersion4SchemaContract(ctx context.Context, connection *sql.Conn) error {
	actual, err := BuildSchemaContract(ctx, connection, 4)
	if err != nil {
		return err
	}
	if !bytes.Equal(actual, frozenVersion4Contract) {
		return fmt.Errorf("validate version 4 schema contract: digest %x, want %s", sha256.Sum256(actual), version4ContractDigest)
	}
	return nil
}

func mustDecodeVersion4Contract() []byte {
	compressed, err := base64.StdEncoding.DecodeString(version4ContractGZIPBase64)
	if err != nil {
		panic(fmt.Sprintf("decode frozen version 4 contract: %v", err))
	}
	reader, err := gzip.NewReader(bytes.NewReader(compressed))
	if err != nil {
		panic(fmt.Sprintf("open frozen version 4 contract: %v", err))
	}
	contract, err := io.ReadAll(io.LimitReader(reader, 1024*1024))
	if err != nil {
		panic(fmt.Sprintf("read frozen version 4 contract: %v", err))
	}
	if err := reader.Close(); err != nil {
		panic(fmt.Sprintf("close frozen version 4 contract: %v", err))
	}
	digest := sha256.Sum256(contract)
	if hex.EncodeToString(digest[:]) != version4ContractDigest {
		panic(fmt.Sprintf("frozen version 4 contract digest = %x, want %s", digest, version4ContractDigest))
	}
	return contract
}
